form:Form.form:Scripts:
		function LoadForm()
{
	if (Ctrl('main').GetMode() !='LIST')	
	{
		CtrlEnabled("EDIT", !(parseInt(Ctrl('e_bloqueo').GetXValue())&1));
		CtrlEnabled("DELETE", !(parseInt(Ctrl('e_bloqueo').GetXValue())&2));		
	}
	else
	{		
		CtrlEnabled("EDIT", !(parseInt(Ctrl('LIST').GetSelectAttrValue('e_bloqueo'))&1));
		CtrlEnabled("DELETE", !(parseInt(Ctrl('LIST').GetSelectAttrValue('e_bloqueo'))&2));		
	}
}

function ChangeSelect(lvObj)
{	
	CtrlEnabled("EDIT", !(parseInt(lvObj.GetSelectAttrValue('e_bloqueo'))&1));
	CtrlEnabled("DELETE", !(parseInt(lvObj.GetSelectAttrValue('e_bloqueo'))&2));		                         	
	Ctrl("color").SetCValue(lvObj.GetSelectAttrValue("c_color"));
	Ctrl("id").SetCValue(lvObj.GetSelectAttrValue("id"));
}    

function SetValues()
{
	switch (Ctrl('c_clase').GetXValue())
	{   
		case "1":
		 Ctrl('c_color').SetXValue('34C500');    
		 Ctrl('e_sumariza_pre').SetXValue('1');    
		 Ctrl('e_sumariza_aus').SetXValue('2');    
		 Ctrl('oi_tipohora_exc').SetXValue('');    
		 Ctrl('oi_tipohora_aus').SetXValue('');    		
		 Ctrl('l_requiereaut').SetXValue('0');    
		 Ctrl('e_tolpreing').SetXValue('30');    
		 Ctrl('e_tolposing').SetXValue('10');    
		 Ctrl('e_tolpreegr').SetXValue('15');    
		 Ctrl('e_tolposegr').SetXValue('45');    
		break;

		case "2":
			Ctrl('c_color').SetXValue('0B00E4');
			Ctrl('e_sumariza_pre').SetXValue('1');    
 		  Ctrl('e_sumariza_aus').SetXValue('2');    
			Ctrl('oi_tipohora_exc').SetXValue('');    
			Ctrl('oi_tipohora_aus').SetXValue('1001');    		
			Ctrl('l_requiereaut').SetXValue('1');    
			Ctrl('e_tolpreing').SetXValue('10');    
			Ctrl('e_tolposing').SetXValue('5');    
			Ctrl('e_tolpreegr').SetXValue('10');    
			Ctrl('e_tolposegr').SetXValue('5');              
		break;

		case "3":
			Ctrl('c_color').SetXValue('0B00E4');
			Ctrl('e_sumariza_pre').SetXValue('1');    
 		  Ctrl('e_sumariza_aus').SetXValue('0');    
			Ctrl('oi_tipohora_exc').SetXValue('');    
			Ctrl('oi_tipohora_aus').SetXValue('');    		
			Ctrl('l_requiereaut').SetXValue('0');    
			Ctrl('e_tolpreing').SetXValue('10');    
			Ctrl('e_tolposing').SetXValue('5');    
			Ctrl('e_tolpreegr').SetXValue('10');    
			Ctrl('e_tolposegr').SetXValue('5');              
		break;

		case "4":
			Ctrl('c_color').SetXValue('FFF100');			
			Ctrl('e_sumariza_pre').SetXValue('2');    
 		  Ctrl('e_sumariza_aus').SetXValue('0');    
			Ctrl('oi_tipohora_exc').SetXValue('1003');    
			Ctrl('oi_tipohora_aus').SetXValue('');    		
			Ctrl('l_requiereaut').SetXValue('0');    
			Ctrl('e_tolpreing').SetXValue('');    
			Ctrl('e_tolposing').SetXValue('');    
			Ctrl('e_tolpreegr').SetXValue('');    
			Ctrl('e_tolposegr').SetXValue('');                
		break;

		case "5":
			Ctrl('c_color').SetXValue('C57100');						
			Ctrl('e_sumariza_pre').SetXValue('2');    
 		  Ctrl('e_sumariza_aus').SetXValue('1');    
			Ctrl('oi_tipohora_exc').SetXValue('1003');    
			Ctrl('oi_tipohora_aus').SetXValue('');    		
			Ctrl('l_requiereaut').SetXValue('0');    
			Ctrl('e_tolpreing').SetXValue('');    
			Ctrl('e_tolposing').SetXValue('');    
			Ctrl('e_tolpreegr').SetXValue('');    
			Ctrl('e_tolposegr').SetXValue('');                                
		break;	  
	}
}

function Change()
{
	if (Ctrl("main").GetMode()=="SHOW")
	{
		Ctrl('main').DoEvent('LoadDDO');
	}
	if (Ctrl("main").GetMode()=="LIST")
	{
		Ctrl('main').DoEvent('AfterColor');
	}

}
